# Clean rewritten version

Here’s a readable equivalent:

```js
const TAU = 6.283;
const PHI = 1.618;
const SQRT1_2 = 0.707;

const config = {
  attraction: 4000,
  frictionCoeff: 0.004,
  amplification: 0.92,
  dispersal: 0.0003,
  streamMax: 40,
  streamDecay: 0.04,
  theta: 0.06
};

const nodes = [
  { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const links = [
  { a: 'hub',   b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub',   b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub',   b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub',   b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub',   b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

const view = { x: 400, y: 300, zoom: 1 };
const targetView = { x: 400, y: 300, zoom: 1 };

const stream = [];
let tick = 0;

function getNodeById(id) {
  return nodes.find(n => n.id === id) || null;
}

function updatePhysics() {
  // Pairwise repulsion
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const dx = nodes[i].x - nodes[j].x;
      const dy = nodes[i].y - nodes[j].y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;
      const force = config.attraction / (dist * dist);
      const fx = dx / dist * force;
      const fy = dy / dist * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // Springs
  for (let i = 0; i < links.length; i++) {
    const n1 = getNodeById(links[i].a);
    const n2 = getNodeById(links[i].b);
    if (!n1 || !n2) continue;

    const dx = n2.x - n1.x;
    const dy = n2.y - n1.y;
    const dist = Math.sqrt(dx * dx + dy * dy) || 1;
    const stretch = dist - links[i].rest;
    const force = (links[i].k || config.dispersal) * stretch;

    n1.vx += dx / dist * force;
    n1.vy += dy / dist * force;
    n2.vx -= dx / dist * force;
    n2.vy -= dy / dist * force;
  }

  // Centering + damping + integrate
  for (let i = 0; i < nodes.length; i++) {
    const n = nodes[i];
    n.vx += (400 - n.x) * config.frictionCoeff;
    n.vy += (300 - n.y) * config.frictionCoeff;
    n.vx *= config.amplification;
    n.vy *= config.amplification;
    n.x += n.vx;
    n.y += n.vy;
  }
}

function spawnParticle() {
  if (stream.length >= config.streamMax) return;

  const node = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * TAU;
  const speed = 0.3 + Math.random() * SQRT1_2;

  stream.push({
    x: node.x,
    y: node.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * PHI + SQRT1_2)
  });
}

function updateParticles() {
  for (let i = stream.length - 1; i >= 0; i--) {
    const p = stream[i];
    p.vx *= 1 - config.streamDecay * 0.125;
    p.vy *= 1 - config.streamDecay * 0.125;
    p.x += p.vx;
    p.y += p.vy;
    p.age++;

    if (p.age > p.maxAge) {
      stream.splice(i, 1);
    }
  }
}

function updateView() {
  view.x += (targetView.x - view.x) * config.theta;
  view.y += (targetView.y - view.y) * config.theta;
  view.zoom += (targetView.zoom - view.zoom) * config.theta;
}

function frame() {
  updatePhysics();
  updateParticles();
  updateView();

  if (tick % 3 === 0) {
    spawnParticle();
  }

  tick++;
}

setInterval(frame, 16);
```

